// RemoveParent relationship.
// Sets o.R.Parent to nil.
// Removes o from all passed in related items' relationships struct.
func (o *Organisation) RemoveParent(ctx context.Context, exec boil.ContextExecutor, related *Organisation) error {
	var err error

	queries.SetScanner(&o.ParentID, nil)
	if _, err = o.Update(ctx, exec, boil.Whitelist("parent_id")); err != nil {
		return errors.Wrap(err, "failed to update local table")
	}

	if o.R != nil {
		o.R.Parent = nil
	}
	if related == nil || related.R == nil {
		return nil
	}

	for i, ri := range related.R.ParentOrganisations {
		if queries.Equal(o.ParentID, ri.ParentID) {
			continue
		}

		ln := len(related.R.ParentOrganisations)
		if ln > 1 && i < ln-1 {
			related.R.ParentOrganisations[i] = related.R.ParentOrganisations[ln-1]
		}
		related.R.ParentOrganisations = related.R.ParentOrganisations[:ln-1]
		break
	}
	return nil
}

