// RemoveParentOrganisations relationships from objects passed in.
// Removes related items from R.ParentOrganisations (uses pointer comparison, removal does not keep order)
// Sets related.R.Parent.
func (o *Organisation) RemoveParentOrganisations(ctx context.Context, exec boil.ContextExecutor, related ...*Organisation) error {
	if len(related) == 0 {
		return nil
	}

	var err error
	for _, rel := range related {
		queries.SetScanner(&rel.ParentID, nil)
		if rel.R != nil {
			rel.R.Parent = nil
		}
		if _, err = rel.Update(ctx, exec, boil.Whitelist("parent_id")); err != nil {
			return err
		}
	}
	if o.R == nil {
		return nil
	}

	for _, rel := range related {
		for i, ri := range o.R.ParentOrganisations {
			if rel != ri {
				continue
			}

			ln := len(o.R.ParentOrganisations)
			if ln > 1 && i < ln-1 {
				o.R.ParentOrganisations[i] = o.R.ParentOrganisations[ln-1]
			}
			o.R.ParentOrganisations = o.R.ParentOrganisations[:ln-1]
			break
		}
	}

	return nil
}

